def solve(disk_size, used_space):
    if disk_size <= 0:
        raise ValueError("Disk size must be greater than zero.")
    if used_space < 0:
        raise ValueError("Used space cannot be negative.")
    if used_space > disk_size:
        raise ValueError("Used space cannot exceed disk size.")

    free_space = disk_size - used_space
    return free_space
